import React, { useState } from "react";
import "../styles/search.css";
const Search = () => {
  // States to store form inputs
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [date, setDate] = useState("");

  // State to silently store only the current search
  const [currentSearch, setCurrentSearch] = useState(null);

  // Function to handle form submission
  const handleSearch = () => {
    if (!from || !to || !date) {
      alert("Please fill all the fields.");
      return;
    }

    // Store the current search data and overwrite previous data
    const newSearch = { from, to, date };
    setCurrentSearch(newSearch);

    // Clear the form fields
    setFrom("");
    setTo("");
    setDate("");

    // Log the stored data for debugging
    console.log("Stored Search Data: ", newSearch);
    console.log(currentSearch);
  };

  return (
  <div className="container">
    <div className="search-container">
      {/* Input Fields */}
      <div className="input-box">
     
        <input
          type="text"
          placeholder="Enter source"
          value={from}
          onChange={(e) => setFrom(e.target.value)}
        />
      </div>
      <div className="input-box">
     
        <input
          type="text"
          placeholder="Enter destination"
          value={to}
          onChange={(e) => setTo(e.target.value)}
        />
      </div>
      <div className="input-box">
    
        <input
          type="date"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />
      </div>

      {/* Search Button */}
      <button onClick={handleSearch} className="search-btn">Search Buses</button>
    </div>
    
    </div>
  );
};
export default Search;
